// Test stackalloc with native-sized integer types (nint / nuint)

Console.WriteLine($"IntPtr.Size = {IntPtr.Size} bytes (running as {IntPtr.Size * 8}-bit)");
Console.WriteLine();

// stackalloc Span<nint>
Span<nint> signed = stackalloc nint[5];
for (int i = 0; i < signed.Length; i++)
    signed[i] = i * 10;

Console.WriteLine("Span<nint> via stackalloc:");
foreach (var v in signed)
    Console.Write($"  {v}");
Console.WriteLine();

// stackalloc Span<nuint>
Span<nuint> unsigned = stackalloc nuint[5];
for (int i = 0; i < unsigned.Length; i++)
    unsigned[i] = (nuint)(i * 100);

Console.WriteLine("Span<nuint> via stackalloc:");
foreach (var v in unsigned)
    Console.Write($"  {v}");
Console.WriteLine();

Console.WriteLine();
Console.WriteLine("Success — stackalloc works with both nint and nuint.");

